  ('p0000001-0000-0000-0000-000000000001','notion-second-brain',       'c6666666-6666-6666-6666-666666666666','notion','published','{"en":"Notion Second Brain","ar":"العقل الثاني — Notion"}','{"en":"All-in-one Notion system for capturing, organizing, and retrieving knowledge.","ar":"نظام Notion شامل لتسجيل وتنظيم واسترجاع المعرفة."}','{"en":"A complete PARA + Zettelkasten workspace built inside Notion. Capture ideas, organize projects, and retrieve knowledge in seconds. Includes 15 linked databases, 40+ templates, and a quickstart video.","ar":"مساحة عمل PARA + Zettelkasten كاملة داخل Notion. سجّل الأفكار، نظّم المشاريع، واسترجع المعرفة في ثوانٍ. تتضمن ١٥ قاعدة بيانات مترابطة، ٤٠+ قالب، وفيديو بدء سريع."}','[{"en":"15 linked databases","ar":"١٥ قاعدة بيانات مترابطة"},{"en":"PARA + Zettelkasten system","ar":"نظام PARA + Zettelkasten"},{"en":"40+ page templates","ar":"٤٠+ قالب صفحة"},{"en":"Quickstart video (Arabic + English)","ar":"فيديو البدء السريع (عربي + إنجليزي)"},{"en":"Lifetime updates","ar":"تحديثات مدى الحياة"}]','',2999,4999,'USD', ARRAY['en','ar'],'personal_use',5,true,342,4.82,48,now()),
  ('p0000002-0000-0000-0000-000000000002','saudi-sme-financial-model','c2222222-2222-2222-2222-222222222222','excel','published','{"en":"Saudi SME Financial Model","ar":"نموذج مالي — شركات صغيرة سعودية"}','{"en":"Investor-ready Excel model for Saudi startups and SMEs.","ar":"نموذج Excel جاهز للمستثمرين لشركات ناشئة وصغيرة في السعودية."}','{"en":"Built specifically for Saudi market — includes revenue projections, P&L, balance sheet, cash flow, cap table, valuation, and Zakat calculation. Fully formula-driven with tutorial notes in every sheet.","ar":"مبني خصيصاً للسوق السعودي — يتضمن توقعات الإيرادات، الأرباح والخسائر، الميزانية العمومية، التدفق النقدي، جدول الملكية، التقييم، وحساب الزكاة. كل المعادلات مدفوعة بالصيغ مع ملاحظات تعليمية في كل شيت."}','[{"en":"3-year projections","ar":"توقعات ثلاث سنوات"},{"en":"P&L + Balance Sheet + Cash Flow","ar":"أرباح وخسائر + ميزانية عمومية + تدفق نقدي"},{"en":"Cap Table + Valuation","ar":"جدول ملكية + تقييم"},{"en":"Zakat-ready calculations","ar":"حسابات جاهزة للزكاة"},{"en":"Tutorial notes in every sheet","ar":"ملاحظات توضيحية في كل شيت"}]','',5999,9999,'USD', ARRAY['en','ar'],'business_use',5,true,215,4.75,31,now()),
  ('p0000003-0000-0000-0000-000000000003','chatgpt-arabic-marketing','c3333333-3333-3333-3333-333333333333','prompt_pack','published','{"en":"ChatGPT Arabic Marketing Pack","ar":"حزمة تسويق عربي — ChatGPT"}','{"en":"250+ battle-tested Arabic marketing prompts.","ar":"٢٥٠+ برومبت تسويق عربي مجربة."}','{"en":"Copywriters and social media managers in the Gulf use these prompts daily. Covers ad copy, email sequences, Instagram captions, LinkedIn posts, landing pages, and SEO meta descriptions — all in native Arabic with dialect options.","ar":"يستخدم هؤلاء الناسخون ومديرو التواصل الاجتماعي في الخليج هذه البرومبتات يومياً. تغطي نصوص الإعلانات، سلاسل البريد، كابشنات إنستقرام، منشورات لينكدإن، صفحات الهبوط، ووصف SEO — كلها بالعربية الفصحى مع خيارات لهجاتية."}','[{"en":"250+ prompts","ar":"٢٥٠+ برومبت"},{"en":"Ad copy + email + social","ar":"إعلانات + بريد + سوشل"},{"en":"SEO meta descriptions","ar":"أوصاف SEO"},{"en":"Dialect-aware Arabic","ar":"عربية واعية باللهجات"},{"en":"Sorted by use case","ar":"مرتبة حسب الاستخدام"}]','',1499,2499,'USD', ARRAY['en','ar'],'commercial_use',5,false,528,4.68,72,now()),
  ('p0000004-0000-0000-0000-000000000004','gulf-hr-policy-handbook','c1111111-1111-1111-1111-111111111111','pdf','published','{"en":"Gulf HR Policy Handbook","ar":"دليل سياسات الموارد البشرية — الخليج"}','{"en":"Complete HR policy template compliant with GCC labor laws.","ar":"قالب سياسات موارد بشرية كامل متوافق مع قوانين العمل الخليجية."}','{"en":"A 90-page handbook covering recruitment, onboarding, leave policies, performance management, termination procedures, and remote-work guidelines. Written by a certified GCC HR consultant and reviewed by a Saudi labor lawyer.","ar":"دليل ٩٠ صفحة يغطي التوظيف، الانضمام، سياسات الإجازة، إدارة الأداء، إجراءات إنهاء الخدمة، وإرشادات العمل عن بُعد. مكتوب من قِبل مستشار موارد بشرية معتمد في الخليج ومراجع من قِبل محامي سعودي مختص."}','[{"en":"90 pages, editable Word + PDF","ar":"٩٠ صفحة، Word + PDF قابلين للتعديل"},{"en":"GCC compliant","ar":"متوافق مع قوانين الخليج"},{"en":"Recruitment to termination","ar":"من التوظيف حتى إنهاء الخدمة"},{"en":"Remote work addendum","ar":"ملحق العمل عن بُعد"},{"en":"Arabic + English side-by-side","ar":"عربي + إنجليزي جنباً إلى جنب"}]','',4999,7999,'USD', ARRAY['en','ar'],'business_use',5,true,128,4.91,14,now()),
  ('p0000005-0000-0000-0000-000000000005','ecommerce-kit-notion','c6666666-6666-6666-6666-666666666666','notion','published','{"en":"E-commerce Kit — Notion","ar":"طقم التجارة الإلكترونية — Notion"}','{"en":"Run your e-commerce business from one Notion dashboard.","ar":"أدر تجارتك الإلكترونية من لوحة Notion واحدة."}','{"en":"Track inventory, suppliers, orders, customers, finances, and marketing campaigns in a single Notion workspace. Built for Shopify, WooCommerce, and Instagram sellers in the Gulf. Includes automation recipes and Zapier templates.","ar":"تتبع المخزون، الموردين، الطلبات، العملاء، المالية، والحملات التسويقية في مساحة عمل Notion واحدة. مبني لبائعي Shopify وWooCommerce وإنستقرام في الخليج. تتضمن وصفات أتمتة وقالب Zapier."}','[{"en":"Inventory + orders + CRM","ar":"مخزون + طلبات + CRM"},{"en":"Suppliers database","ar":"قاعدة بيانات الموردين"},{"en":"Finance tracker","ar":"متتبع المالية"},{"en":"Marketing campaign board","ar":"لوحة الحملات التسويقية"},{"en":"Zapier automations included","ar":"أتمتات Zapier مرفقة"}]','',2499,3999,'USD', ARRAY['en','ar'],'commercial_use',5,false,89,4.55,22,now()),
  ('p0000006-0000-0000-0000-000000000006','notion-ultimate-life-planner','c6666666-6666-6666-6666-666666666666','notion','published','{"en":"Ultimate Life Planner — Notion","ar":"مخطط الحياة الشامل — Notion"}','{"en":"Plan your goals, habits, and daily tasks with this all-in-one Notion workspace.","ar":"خطط لأهدافك، عاداتك، ومهامك اليومية مع مساحة العمل الشاملة هذه في Notion."}','{"en":"Inspired by the Getting Things Done methodology, this planner combines yearly goals, quarterly reviews, habit trackers, project roadmaps, and daily journaling. Designed for busy professionals who want clarity without complexity.","ar":"مستوحى من منهجية Getting Things Done، يجمع هذا المخطط بين الأهداف السنوية، المراجعات الفصلية، متتبعات العادات، خرائط المشاريع، والتدوين اليومي. مصمم للمحترفين المشغولين الذين يريدون وضوحاً دون تعقيد."}','[{"en":"Yearly + quarterly + monthly views","ar":"عرض سنوي + فصلي + شهري"},{"en":"Habit tracker with streaks","ar":"متتبع العادات مع سلاسل"},{"en":"Project roadmap","ar":"خريطة مشروع"},{"en":"Daily journaling template","ar":"قالب التدوين اليومي"},{"en":"GTD-inspired workflow","ar":"سير عمل مستوحى من GTD"}]','',1999,3499,'USD', ARRAY['en','ar'],'personal_use',5,false,156,4.71,29,now()),
  ('p0000007-0000-0000-0000-000000000007','gulf-content-calendar-2026','c2222222-2222-2222-2222-222222222222','excel','published','{"en":"Gulf Content Calendar 2026","ar":"رزنامة المحتوى ٢٠٢٦ — الخليج"}','{"en":"A full-year content calendar tailored for Gulf influencers and brands.","ar":"رزنامة محتوى للعام الكامل مخصصة لمؤثرين وعلامات تجارية في الخليج."}','{"en":"52 weeks of content themes, posting schedules, hashtag sets, and campaign slots aligned with Saudi and UAE holidays (Founding Day, Eid, Ramadan, National Day, Black Friday). Includes an AI prompt companion for every week.","ar":"٥٢ أسبوعاً من مواضيع المحتوى، جداول النشر، مجموعات الهاشتاق، ومواعيد الحملات المتوافقة مع إجازات السعودية والإمارات (يوم التأسيس، العيد، رمضان، اليوم الوطني، الجمعة السوداء). تتضمن رفيق برومبت AI لكل أسبوع."}','[{"en":"52 weeks pre-filled","ar":"٥٢ أسبوعاً مُعبأ مسبقاً"},{"en":"Saudi + UAE holiday slots","ar":"فترات الإجازات السعودية + الإماراتية"},{"en":"Hashtag sets per week","ar":"مجموعات هاشتاق أسبوعية"},{"en":"Campaign planning tabs","ar":"تبويبات تخطيط الحملات"},{"en":"AI prompt companion","ar":"رفيق برومبت AI"}]','',1999,2999,'USD', ARRAY['en','ar'],'commercial_use',5,false,67,4.62,13,now()),
  ('p0000008-0000-0000-0000-000000000008','python-web-scraper-starter','c5555555-5555-5555-5555-555555555555','code','published','{"en":"Python Web Scraper Starter","ar":"بداية سكربت بايثون للتحليل"}','{"en":"Production-ready Python scraper with proxy rotation, retry logic, and data export.","ar":"سكربت بايثون جاهز للإنتاج مع تدوير بروكسي، منطق إعادة المحاولة، وتصدير البيانات."}','{"en":"Built for e-commerce intelligence, lead generation, and price monitoring. Includes async requests via aiohttp, BeautifulSoup parsing, rotating proxy support, SQLite caching, and export to CSV/JSON/Excel. Fully commented in Arabic and English.","ar":"مبني لذكاء التجارة الإلكترونية، توليد العملاء المحتملين، ومراقبة الأسعار. يتضمن طلبات async عبر aiohttp، تحليل BeautifulSoup، دعم بروكسي متدوّر، تخزين مؤقت SQLite، وتصدير إلى CSV/JSON/Excel. مُعلق بالكامل بالعربية والإنجليزية."}','[{"en":"Async aiohttp requests","ar":"طلبات aiohttp async"},{"en":"BeautifulSoup + CSS selectors","ar":"BeautifulSoup + محددات CSS"},{"en":"Rotating proxy support","ar":"دعم بروكسي متدوّر"},{"en":"SQLite caching layer","ar":"طبقة تخزين مؤقت SQLite"},{"en":"Export CSV/JSON/Excel","ar":"تصدير CSV/JSON/Excel"}]','',1499,2499,'USD', ARRAY['en','ar'],'commercial_use',5,false,203,4.78,41,now()),
  ('p0000009-0000-0000-0000-000000000009','brand-identity-kit-figma','c1111111-1111-1111-1111-111111111111','template','published','{"en":"Brand Identity Kit — Figma","ar":"طقم هوية العلامة التجارية — Figma"}','{"en":"Complete Figma brand kit with logo variations, color system, typography, and social templates.","ar":"طقم Figma شاملة مع متغيرات الشعار، نظام الألوان، الطباعة، وقوالب التواصل."}','{"en":"Designed for startups and agencies in MENA. Includes logo grid, primary and secondary colors with hex codes, font pairings for Arabic and English, Instagram story/post templates, business card mockup, and a brand guidelines page. Everything is editable in Figma with auto-layout.","ar":"مصمم للشركات الناشئة والوكالات في الشرق الأوسط وشمال إفريقيا. يتضمن شبكة الشعار، الألوان الأساسية والثانوية مع أكواد hex، أزواج الخطوط العربية والإنجليزية، قوالب ستوري/بوست إنستقرام، نموذج بطاقة أعمال، وصفحة إرشادات العلامة. كل شيء قابل للتعديل في Figma مع auto-layout."}','[{"en":"Logo grid + variations","ar":"شبكة الشعار + المتغيرات"},{"en":"Arabic + English font pairings","ar":"أزواج خطوط عربية + إنجليزية"},{"en":"Instagram story + post templates","ar":"قوالب ستوري + بوست إنستقرام"},{"en":"Business card mockup","ar":"نموذج بطاقة أعمال"},{"en":"Brand guidelines page","ar":"صفحة إرشادات العلامة"}]','',3499,5499,'USD', ARRAY['en','ar'],'commercial_use',5,true,94,4.85,17,now()),
  ('p0000010-0000-0000-0000-000000000010','midjourney-architecture-prompts','c3333333-3333-3333-3333-333333333333','prompt_pack','published','{"en":"Midjourney Architecture Prompts","ar":"برومبتات معمارية — Midjourney"}','{"en":"150 prompts to generate architectural renders, interiors, and landscape concepts.","ar":"١٥٠ برومبت لتوليد رسومات معمارية، داخليات، ومفاهيم مناظر طبيعية."}','{"en":"Created by an architect who uses Midjourney daily for client presentations. Includes styles from Zaha Hadid to traditional Arabic courtyard houses. Each prompt comes with parameter variations, aspect ratio recommendations, and example outputs.","ar":"مُنشأة من قِبل مهندس معماري يستخدم Midjourney يومياً للعروض التقديمية للعملاء. تتضمن أنماطاً من زها حديد إلى المنازل العربية التقليدية ذات الفناء. كل برومبت يأتي مع متغيرات المعاملات، توصيات نسبة العرض، ومخرجات مثالية."}','[{"en":"150 architecture prompts","ar":"١٥٠ برومبت معماري"},{"en":"Interior + exterior + landscape","ar":"داخلي + خارجي + مناظر طبيعية"},{"en":"Style variations included","ar":"متغيرات الأنماط مرفقة"},{"en":"Parameter + aspect ratio guide","ar":"دليل المعاملات + نسبة العرض"},{"en":"Example outputs gallery","ar":"معرض المخرجات المثالية"}]','',1299,1999,'USD', ARRAY['en','ar'],'personal_use',5,false,312,4.69,55,now()),
  ('p0000011-0000-0000-0000-000000000011','freelance-contract-template-ar','c1111111-1111-1111-1111-111111111111','word','published','{"en":"Freelance Contract Template (AR)","ar":"نموذج عقد مستقل (عربي)"}','{"en":"Legally-informed Arabic freelance contract template reviewed by a GCC lawyer.","ar":"قالب عقد مستقل عربي مُستنبت قانونياً ومراجع من قِبل محامٍ خليجي."}','{"en":"Covers scope of work, payment terms, milestone schedule, intellectual property transfer, revision limits, late payment penalties, and termination clauses. Written in formal Arabic ( fus.ha ) with side-by-side English annotations for international clients.","ar":"يغطي نطاق العمل، شروط الدفع، جدول الملفات، نقل الملكية الفكرية، حدود المراجعة، عقوبات التأخير، وبنود إنهاء الخدمة. مكتوب بالعربية الفصحى مع تعليقات إنجليزية جنباً إلى جنب للعملاء الدوليين."}','[{"en":"Scope + payment + milestones","ar":"النطاق + الدفع + الملفات"},{"en":"IP transfer clause","ar":"بند نقل الملكية الفكرية"},{"en":"Late payment penalties","ar":"عقوبات التأخير في الدفع"},{"en":"Termination clauses","ar":"بنود إنهاء الخدمة"},{"en":"Arabic + English annotations","ar":"تعليقات عربية + إنجليزية"}]','',999,1499,'USD', ARRAY['en','ar'],'commercial_use',5,false,418,4.73,62,now()),
  ('p0000012-0000-0000-0000-000000000012','saram-dashboard-excel','c2222222-2222-2222-2222-222222222222','excel','published','{"en":"SARAM Dashboard — Excel","ar":"لوحة SARAM — Excel"}','{"en":"Track your Saudi personal investments, Zakat, and net worth in one Excel dashboard.","ar":"تتبع استثماراتك الشخصية السعودية، زكاتك، وثروتك الصافية في لوحة Excel واحدة."}','{"en":"Built for Saudi residents who invest in stocks, real estate, and crypto. Automatically calculates Zakat on tradable assets using the Nisab threshold from SAMA. Includes portfolio allocation charts, dividend tracker, and capital gains log.","ar":"مبني لمقيمي السعودية الذين يستثمرون في الأسهم، العقارات، والعملات الرقمية. يحسب الزكاة تلقائياً على الأصول القابلة للتداول باستخدام عتبة النصاب من SAMA. يتضمن رسوم تخصيص المحفظة، متتبع الأرباح، وسجل الأرباح الرأسمالية."}','[{"en":"Zakat auto-calculation (SAMA Nisab)","ar":"حساب الزكاة التلقائي (نصاب SAMA)"},{"en":"Stocks + real estate + crypto","ar":"أسهم + عقارات + عملات رقمية"},{"en":"Portfolio allocation charts","ar":"رسوم تخصيص المحفظة"},{"en":"Dividend tracker","ar":"متتبع الأرباح"},{"en":"Capital gains log","ar":"سجل الأرباح الرأسمالية"}]','',3999,5999,'USD', ARRAY['en','ar'],'personal_use',5,true,176,4.88,24,now()),
