  ('p0000014-0000-0000-0000-000000000014','email-marketing-swipe-file','c4444444-4444-4444-4444-444444444444','pdf','published','{"en":"Email Marketing Swipe File","ar":"ملف البريد التسويقي الجاهز"}','{"en":"100 high-converting email templates for e-commerce and SaaS.","ar":"١٠٠ قالب بريد إلكتروني عالي التحويل للتجارة الإلكترونية وSaaS."}','{"en":"Written by a copywriter who sold $2M+ of digital products via email. Covers welcome sequences, product launches, cart abandonment, win-back campaigns, flash sales, and post-purchase upsells. Each template includes subject lines, preheaders, and psychological triggers.","ar":"مكتوب من قِبل ناسخ باع منتجات رقمية بأكثر من ٢ مليون دولار عبر البريد. يغطي سلاسل الترحيب، إطلاق المنتجات، تخلي عن السلة، حملات الاستعادة، المبيعات السريعة، والمبيعات الإضافية بعد الشراء. كل قالب يتضمن أسطر الموضوع، الرؤوس المسبقة، والمحفزات النفسية."}','[{"en":"100 email templates","ar":"١٠٠ قالب بريد"},{"en":"Welcome + launch + abandonment","ar":"ترحيب + إطلاق + تخلي"},{"en":"Subject lines + preheaders","ar":"أسطر الموضوع + الرؤوس المسبقة"},{"en":"Psychological triggers explained","ar":"محفزات نفسية موضحة"},{"en":"Arabic + English versions","ar":"نسخ عربية + إنجليزية"}]','',2499,3999,'USD', ARRAY['en','ar'],'commercial_use',5,true,291,4.81,38,now()),
