-- ----- admin user (password = souq-admin-2026) -----------------------------
values (
  'a0000000-0000-0000-0000-000000000001',
  'admin@souq.gg',
  'scrypt$souqadmin2026salt$8249cddb902245b3652a224b457e465f0335dd83613654d70243dd96156117b1239ad782e58432169226ea569f612124651ade523073557212b521088400bbf0',
