-- ----- categories -----------------------------------------------------------
on conflict (slug) do nothing;

-- ----- 25 products (mixed types, Arabic-first) ----------------------------

-- ----- product_files: add a dummy file for each product so downloads work ----
select
  gen_random_uuid(),
  id,
  title->>'en' || '.zip',
  '/uploads/products/' || slug || '.zip',
  (floor(random()*50)::int + 1) * 1024 * 1024,
  'application/zip'
from products;

